namespace sv_47ac62e56a5e4399ac47b052932edcc2.Models;

public class ApplicationData
{
    // Step 1 – Personal Info
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";

    // Step 2 – Experience
    public List<JobEntry> JobHistory { get; set; } = [];

    // Step 3 – References
    public List<ReferenceContact> References { get; set; } = [];

    // Track which steps have been completed (1-based)
    public HashSet<int> CompletedSteps { get; set; } = [];
}

public class JobEntry
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public string Years { get; set; } = "";
}

public class ReferenceContact
{
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";
    public string Relationship { get; set; } = "";
}

using System.Collections.Concurrent;
using sv_47ac62e56a5e4399ac47b052932edcc2.Models;

namespace sv_47ac62e56a5e4399ac47b052932edcc2.Services;

/// <summary>
/// Singleton service that stores wizard state keyed by a session identifier.
/// Both the static SSR layout and interactive server pages resolve the same
/// instance, so they share state as long as they use the same session key.
/// </summary>
public class WizardStateService
{
    public const string CookieName = "WizardSessionId";

    private readonly ConcurrentDictionary<string, ApplicationData> _store = new();

    public ApplicationData GetOrCreate(string sessionId)
        => _store.GetOrAdd(sessionId, _ => new ApplicationData());

    public ApplicationData? TryGet(string sessionId)
        => _store.TryGetValue(sessionId, out var data) ? data : null;

    public void Remove(string sessionId)
        => _store.TryRemove(sessionId, out _);

    /// <summary>
    /// Reads (or creates) the wizard session cookie and returns the session id.
    /// Safe to call from static SSR where HttpContext is always available.
    /// </summary>
    public static string EnsureSessionId(HttpContext httpContext)
    {
        if (httpContext.Request.Cookies.TryGetValue(CookieName, out var id) && !string.IsNullOrEmpty(id))
            return id;

        id = Guid.NewGuid().ToString("N");
        httpContext.Response.Cookies.Append(CookieName, id, new CookieOptions
        {
            HttpOnly = true,
            SameSite = SameSiteMode.Strict,
            IsEssential = true,
            MaxAge = TimeSpan.FromHours(4)
        });
        return id;
    }
}

