@inherits LayoutComponentBase
@inject Services.WizardStateService WizardState
@inject NavigationManager Nav

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="wizard-progress px-4 py-3">
            <h6 class="mb-2">Job Application — Step @CurrentStep of 4</h6>
            <div class="d-flex gap-2 mb-2">
                @for (int i = 1; i <= 4; i++)
                {
                    var step = i;
                    <a href="@StepUrl(step)"
                       class="wizard-step @(step == CurrentStep ? "active" : "") @(IsCompleted(step) ? "completed" : "")">
                        @StepLabel(step)
                    </a>
                }
            </div>
            <div class="progress" style="height: 6px;">
                <div class="progress-bar" role="progressbar"
                     style="width: @(CurrentStep * 25)%"></div>
            </div>
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    // HttpContext is available here because the layout renders statically (SSR).
    [CascadingParameter]
    public HttpContext? HttpContext { get; set; }

    private string _sessionId = "";
    private Models.ApplicationData? _data;

    private int CurrentStep => Nav.Uri switch
    {
        var u when u.Contains("/apply/experience") => 2,
        var u when u.Contains("/apply/references") => 3,
        var u when u.Contains("/apply/review") => 4,
        _ => 1
    };

    protected override void OnInitialized()
    {
        if (HttpContext is not null)
        {
            _sessionId = Services.WizardStateService.EnsureSessionId(HttpContext);
            _data = WizardState.GetOrCreate(_sessionId);
        }
    }

    private bool IsCompleted(int step) => _data?.CompletedSteps.Contains(step) == true;

    private static string StepUrl(int step) => step switch
    {
        1 => "/apply/personal-info",
        2 => "/apply/experience",
        3 => "/apply/references",
        4 => "/apply/review",
        _ => "/apply/personal-info"
    };

    private static string StepLabel(int step) => step switch
    {
        1 => "Personal Info",
        2 => "Experience",
        3 => "References",
        4 => "Review",
        _ => ""
    };
}

.wizard-progress {
    background-color: #f7f7f7;
    border-bottom: 1px solid #d6d5d5;
}

.wizard-step {
    display: inline-block;
    padding: 0.35rem 0.75rem;
    border-radius: 0.375rem;
    font-size: 0.85rem;
    text-decoration: none;
    color: #6c757d;
    background: #e9ecef;
    transition: background 0.2s;
}

.wizard-step:hover {
    background: #dee2e6;
    text-decoration: none;
}

.wizard-step.active {
    background: #0d6efd;
    color: #fff;
    font-weight: 600;
}

.wizard-step.completed:not(.active) {
    background: #198754;
    color: #fff;
}

