@inject Services.WizardStateService WizardState
@inject NavigationManager Nav
@inject IHttpContextAccessor HttpContextAccessor

<PageTitle>Apply — Personal Info</PageTitle>

<h1>Step 1: Personal Information</h1>

<div class="col-md-6">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <input class="form-control" @bind="_data.Name" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email Address</label>
        <input class="form-control" type="email" @bind="_data.Email" />
    </div>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private Models.ApplicationData _data = new();
    private string _sessionId = "";

    protected override void OnInitialized()
    {
        // HttpContext is only available during the static prerender pass.
