@page "/apply/review"
@layout Layout.WizardLayout
@rendermode InteractiveServer

@inject Services.WizardStateService WizardState
@inject NavigationManager Nav
@inject IHttpContextAccessor HttpContextAccessor

<PageTitle>Apply — Review</PageTitle>

<h1>Step 4: Review Your Application</h1>

<div class="col-md-8">
    <div class="card mb-3 p-3">
        <h5>Personal Information</h5>
        <p><strong>Name:</strong> @_data.Name</p>
        <p><strong>Email:</strong> @_data.Email</p>
    </div>

    <div class="card mb-3 p-3">
        <h5>Work Experience</h5>
        @if (_data.JobHistory.Count == 0)
        {
            <p class="text-muted">No job history entered.</p>
        }
        else
        {
            @foreach (var job in _data.JobHistory)
            {
                <div class="mb-2">
                    <strong>@job.Title</strong> at @job.Company (@job.Years)
                </div>
            }
        }
    </div>

    <div class="card mb-3 p-3">
        <h5>References</h5>
        @if (_data.References.Count == 0)
        {
            <p class="text-muted">No references entered.</p>
        }
        else
        {
            @foreach (var r in _data.References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> — @r.Email (@r.Relationship)
                </div>
            }
        }
    </div>

    <div class="d-flex gap-2">
        <button class="btn btn-secondary" @onclick="Back">← Back</button>
        <button class="btn btn-success" @onclick="Submit">Submit Application</button>
    </div>

    @if (_submitted)
    {
        <div class="alert alert-success mt-3">
            Your application has been submitted successfully!
        </div>
    }
</div>

@code {
    private Models.ApplicationData _data = new();
    private string _sessionId = "";
    private bool _submitted;

    protected override void OnInitialized()
    {
        var httpContext = HttpContextAccessor.HttpContext;
        if (httpContext is not null)
        {
            _sessionId = Services.WizardStateService.EnsureSessionId(httpContext);
            _data = WizardState.GetOrCreate(_sessionId);
        }
    }

    private void Back() => Nav.NavigateTo("/apply/references", forceLoad: true);

    private void Submit()
    {
        _data.CompletedSteps.Add(4);
        _submitted = true;
    }
}

