@page "/apply/personal-info"
@layout Layout.WizardLayout
@rendermode InteractiveServer

@inject Services.WizardStateService WizardState
@inject NavigationManager Nav
@inject IHttpContextAccessor HttpContextAccessor

<PageTitle>Apply — Personal Info</PageTitle>

<h1>Step 1: Personal Information</h1>

<div class="col-md-6">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <input class="form-control" @bind="_data.Name" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email Address</label>
        <input class="form-control" type="email" @bind="_data.Email" />
    </div>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private Models.ApplicationData _data = new();
    private string _sessionId = "";

    protected override void OnInitialized()
    {
        // HttpContext is only available during the static prerender pass.
        // Capture the session key here so it survives into interactive mode.
        var httpContext = HttpContextAccessor.HttpContext;
        if (httpContext is not null)
        {
            _sessionId = Services.WizardStateService.EnsureSessionId(httpContext);
            _data = WizardState.GetOrCreate(_sessionId);
        }
    }

    private void Next()
    {
        _data.CompletedSteps.Add(1);
        Nav.NavigateTo("/apply/experience", forceLoad: true);
    }
}

@page "/apply/experience"
@layout Layout.WizardLayout
@rendermode InteractiveServer

@inject Services.WizardStateService WizardState
@inject NavigationManager Nav
@inject IHttpContextAccessor HttpContextAccessor

<PageTitle>Apply — Experience</PageTitle>

<h1>Step 2: Work Experience</h1>

<div class="col-md-8">
    @for (int i = 0; i < _data.JobHistory.Count; i++)
    {
        var idx = i;
        <div class="card mb-3 p-3">
            <div class="d-flex justify-content-between align-items-start">
                <strong>Job @(idx + 1)</strong>
                <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveJob(idx)">Remove</button>
            </div>
            <div class="mb-2">
                <label class="form-label">Company</label>
                <input class="form-control" @bind="_data.JobHistory[idx].Company" />
            </div>
            <div class="mb-2">
                <label class="form-label">Title</label>
                <input class="form-control" @bind="_data.JobHistory[idx].Title" />
            </div>
            <div class="mb-2">
                <label class="form-label">Years</label>
                <input class="form-control" @bind="_data.JobHistory[idx].Years" />
            </div>
        </div>
    }

    <button class="btn btn-outline-secondary mb-3" @onclick="AddJob">+ Add Job</button>

    <div class="d-flex gap-2">
        <button class="btn btn-secondary" @onclick="Back">← Back</button>
        <button class="btn btn-primary" @onclick="Next">Next →</button>
    </div>
</div>

@code {
    private Models.ApplicationData _data = new();
    private string _sessionId = "";

    protected override void OnInitialized()
    {
        var httpContext = HttpContextAccessor.HttpContext;
        if (httpContext is not null)
        {
            _sessionId = Services.WizardStateService.EnsureSessionId(httpContext);
            _data = WizardState.GetOrCreate(_sessionId);
        }
    }

    private void AddJob() => _data.JobHistory.Add(new Models.JobEntry());
    private void RemoveJob(int idx) => _data.JobHistory.RemoveAt(idx);

    private void Back() => Nav.NavigateTo("/apply/personal-info", forceLoad: true);

    private void Next()
    {
        _data.CompletedSteps.Add(2);
        Nav.NavigateTo("/apply/references", forceLoad: true);
    }
}

@page "/apply/references"
@layout Layout.WizardLayout
@rendermode InteractiveServer

@inject Services.WizardStateService WizardState
@inject NavigationManager Nav
@inject IHttpContextAccessor HttpContextAccessor

<PageTitle>Apply — References</PageTitle>

