                <strong>Reference @(idx + 1)</strong>
                <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveRef(idx)">Remove</button>
            </div>
            <div class="mb-2">
                <label class="form-label">Name</label>
                <input class="form-control" @bind="_data.References[idx].Name" />
            </div>
            <div class="mb-2">
                <label class="form-label">Email</label>
                <input class="form-control" type="email" @bind="_data.References[idx].Email" />
            </div>
            <div class="mb-2">
                <label class="form-label">Relationship</label>
                <input class="form-control" @bind="_data.References[idx].Relationship" />
            </div>
        </div>
    }

    <button class="btn btn-outline-secondary mb-3" @onclick="AddRef">+ Add Reference</button>

    <div class="d-flex gap-2">
        <button class="btn btn-secondary" @onclick="Back">← Back</button>
        <button class="btn btn-primary" @onclick="Next">Next →</button>
    </div>
</div>

@code {
    private Models.ApplicationData _data = new();
    private string _sessionId = "";

    protected override void OnInitialized()
    {
        var httpContext = HttpContextAccessor.HttpContext;
        if (httpContext is not null)
