            _sessionId = Services.WizardStateService.EnsureSessionId(httpContext);
            _data = WizardState.GetOrCreate(_sessionId);
        }
    }

    private void AddRef() => _data.References.Add(new Models.ReferenceContact());
    private void RemoveRef(int idx) => _data.References.RemoveAt(idx);

